const features = [
  {
    title: 'Responsabilité Civile Professionnelle',
    description: 'La RC Pro est obligatoire pour tout professionnel du transport. Elle couvre les dommages causés aux tiers lors de votre activité.',
    icon: '🛡️'
  },
  {
    title: 'Garantie Dommages au Véhicule',
    description: 'Protégez votre véhicule contre les accidents, le vol, l\'incendie et les dommages climatiques. Options adaptées à votre budget.',
    icon: '🚗'
  },
  {
    title: 'Assurance Conducteur',
    description: 'Protégez-vous en cas d\'accident responsable. Couverture des frais médicaux, invalidité et décès.',
    icon: '👤'
  },
  {
    title: 'Protection Juridique',
    description: 'Assistance juridique en cas de litige. Prise en charge des frais de défense et des procédures.',
    icon: '⚖️'
  },
  {
    title: 'Garantie Pierres et Verre',
    description: 'Couverture spécifique pour les vitres et optiques de votre véhicule professionnel.',
    icon: '🔍'
  },
  {
    title: 'Assistance 24h/24',
    description: 'Dépannage et remorquage immédiats en cas de panne ou accident, où que vous soyez.',
    icon: '🚨'
  }
];

export default function Features() {
  return (
    <section id="features" className="py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Nos <span className="text-blue-800">garanties</span> complètes
          </h2>
          <p className="mt-4 text-gray-600 text-lg max-w-2xl mx-auto">
            Des formules adaptées à votre activité de transport professionnel
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {features.map((feature, index) => (
            <div key={index} className="bg-white rounded-2xl p-6 shadow-md hover:shadow-xl transition-shadow">
              <div className="flex items-start gap-4">
                <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center flex-shrink-0">
                  <span className="text-2xl">{feature.icon}</span>
                </div>
                <div>
                  <h3 className="text-lg font-bold text-gray-900 mb-2">{feature.title}</h3>
                  <p className="text-gray-600 text-sm">{feature.description}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
